data:
html ,
body {
    margin: 0;
    padding: 0;
    height: 100%;
}
.ui-content {
    padding: 0;
}
.ui-footer {
    text-align: center;
    padding: 5px 0;
}
.portrait, .portrait #mappage {
    min-height: 0;
}
/*.portrait, .portrait .ui-page{*/
    /*min-height: 0;*/
/*}*/
#mappage, #mappage .ui-content, #map {
    width: 100%;
    height: 100%;
}
.olControlAttribution {
    font-size: 10px;
    bottom: 5px;
    right: 5px;
}
#navigation {
    position: absolute;
    bottom: 70px;
    left: 10px;
    z-index: 1000;
}
#navigation .ui-btn-icon-notext {
    display: block;
    padding: 7px 6px 7px 8px;
}
#title, #tags, #shortdesc {
    display: none;
}
.ui-icon-check {
    opacity: 0.3;
}
.checked .ui-icon-check {
    opacity: 1;
}
.ui-icon-locate {
    background-image: url(img/locate.png);
}
.ui-icon-layers {
    background-image: url(img/openlayers.png);
}
.ui-content .ui-listview-inset, #search_results {
    margin: 1em;
}
.ui-content .ui-listview {
    margin: 0px;
}
#details-list li{
	padding:15px 10px;
}

.footer{
	position: absolute !important ;
	bottom: 0;
	width: 100%;
	padding: 0;
	z-index: 1000;
}

.footer-control-group{
	height:	100%;
	width: 100%;
	margin: 0;
}

.footer-button{
	width: 33%;
}

.footer-control-group .ui-controlgroup-controls {
	width: 100%;
}

.header{
	color: white; !important
}

.header .header-button{
	margin : 0;
}

.checkboxWidth{
	width:	53px;
}

.ui-content {
	padding-bottom: 60px;
}

.table-details{
	border: 0;
	border-spacing: 0;
	padding: 0;
	margin: 0;
}

.table-details th {
	padding: 3px 0;
}

.two-col{
	width: 50%;
	padding: 1px 10px;
}

.left-col{
	text-align: left;
}

.right-col{
	text-align: right;
}

/* Modified at first page loading in javascript*/
.ui-content-smart{
	height: 0;
	width: 0;
}

.commands-table {
	padding: 10px 0;
}

.commands-table thead td{
	border-bottom: 1px solid black;
	font-weight: bold;
	cursor: pointer;
}

.ui-select {
	width: 95% !important;
}

.accordion {
	width: 470px;
}

.ui-state-active a {
	border-bottom: 1px solid #C5DBEC;
}

label.choice {
	padding: 0;
}

.tracking_interval_div {
	border-bottom: 1px dashed #75AD02;
	margin: 2px 0;
	text-align: center;
	color: #4F8CC9;
	font-weight: bold;
	/* height: 80px; */
	font-style: italic;
}

.tracking_interval_div table {
	margin: 0px 0px 5px;
	width: 100%;
}

.tracking_interval_div table td {
	padding: 0;
}

table {
	margin: 0;
}

#notifications .ui-accordion-content-active {
	max-height: 150px;
	height: auto;
}

#notifications .dataTables_wrapper {
	height: auto;
	min-height: 0;
}

#accordionTD {
	vertical-align: top;
}

.olLayerGoogleCopyright {
	top: -1000px;
}

.dataLbl {
	display: none;
}

.dataLayersDiv {
	display: none;
}

.tooltip {
	display: none;
	position: absolute;
	padding: 10px;
	left: 15px;
	font-size: 0.8em;
	background-color: white;
	border: 1px solid #a6c9e2;
	-moz-border-radius: 5px;
	-webkit-border-radius: 5px;
	z-index: 9999;
	top: -10px;
	left: 5px, offset:  20, 0
}

.tabs-bottom .ui-tabs-panel {
	height: 100px;
	overflow: auto;
}

.olControlAttribution {
	bottom: 0px !important
}

/* avoid pink tiles */
.olImageLoadError {
	background-color: transparent !important;
}

#tab-logs .ui-corner-tl {
	display: none;
}

#tab-logs .ui-widget-header {
	background: white;
	border: 1px solid #C5DBEC;
	background: #DFEFFC;
}

TD.adminViewTableHeader {
	font-size: 9pt;
	height: 23px;
	padding-right: 5px;
	padding-left: 5px;
	text-align: right;
}

TD.adminViewTableData {
	height: 23px;
}

ul.ui-tabs-nav {
	font-size: 10px;
}

.ui-tabs-panel {
	font-size: 11px;
}

.linkvehicle .jstree-icon {
	display: none;
}

.labelInput {
	text-align: right;
	font-weight: bold;
	font-size: 12px;
}

.calendarInput {
	text-align: center;
	font-size: 11px;
}

/* Style applied only for Opera */
@media not screen and (1) {
	.ui-tabs .ui-tabs-nav {
		height: 0;
	}
}

.ui-buttonset {
	margin-right: 0;
}

div.devices-tbl .devices-row {
	height: 25px; #
	border-bottom: 1px solid #d0cecf;
	cursor: pointer;
}

img.dev-icon {
	padding-top: 4px;
}

div.dev-selected {
	border-bottom: 1px solid #d0cecf;
	border-top: 1px solid #d0cecf;
	color: #E17009;
}

.devcheck {
	cursor: pointer;
}

div.olControlZoomPanel div {
	width: 36px;
	height: 36px;
/* 	background-image: url(img/mobile-zoombar.png); */
	left: 0;
}


div.olControlZoomPanel .olControlZoomInItemInactive,div.olControlZoomPanel .olControlZoomOutItemInactive
	{
 	background: rgba(0, 0, 0, 0.4); 
	position: absolute;
}

/* Styles for IE 6,7,8,9,10*/
@media \0screen\,screen\9 { 
	div.olControlZoomPanel .olControlZoomInItemInactive,div.olControlZoomPanel .olControlZoomOutItemInactive{
		background-color: #565051; /* for IE - solid color*/
		position: absolute;
	}
}

div.olControlZoomPanel .olControlZoomInItemInactive {
	border-radius: 5px 5px 0 0;
	background-image: url('../../styles/plus.png');
}

div.olControlZoomPanel .olControlZoomOutItemInactive {
	border-radius: 0 0 5px 5px;
	top: 37px;
	background-image: url('../../styles/minus.png');
}

div.olControlZoomPanel .olControlZoomToMaxExtentItemInactive {
	display: none;
}

#title,#tags,#shortdesc {
	display: none;
}

.ollayerGoogleCopyright {
	z-index: 150 !important;
}

.tracking_display {
	padding: 0;
	margin: 0;
}
.tracking_display .main_td {
	width: 150%;
}

.tracking_display th {
	border-bottom: 1px solid black;
	padding: 0;
	margin: 0;
}
.tracking_display td {
	padding-top: 1px;
}

#units-type {
	border: 1px solid #B4B4B4;
	color: #464646;
	background-color: white;
	border-image: initial;
}


/* Begin Draggable styles */

#vert-draggable-div {
	height: 100%;
	width: 100%;
	background-color: #d9d9db;
	z-index: 1009;
	border: none;

}

#horiz-draggable-div {
	margin-left: auto;
	margin-right: auto;
	background-color: white;
	text-align: center;
	z-index: 4001;
}

#draggingCell{
	height: 100%; 
	padding: 0; 
	margin: 0; 
	width: 3px; 
	border: 1px solid #D9D9DB;
	border-top: none;
	border-bottom: none;
}

#dragging-row {
	background-color: #D9D9DB;
}

#vert-separator{
	position:absolute; 
	top: 49%;
}

/* End Draggable styles */

.fixtd {
	width: 10px;
}

.device-popup .ui-dialog-titlebar {
	display: none;
}

.device-popup{
	*height: 350px; /* IE */
}

.tabs-extinfo > div{
	width: 250px;
}
.tabs-extinfoHis > div{
	width: 309px;
}



#tab-device-options>table{
	/* height: 100%; */
	width: 100%;
}

#tab-device-details>table {
	height: 100%; 
	width: 100%;
}

.tabs-extinfo.ui-tabs.ui-widget-content {
	border: #EEE;
}

.tabs-extinfo .ui-widget-header {
	background: #FFF;
	border: #FFF;
}

.tabs-extinfo .ui-tabs-nav.ui-widget-header {
	padding: 0 0 0;
}


.tHis {    
    border: 1px solid #ddd;
    text-align: left;
}
.tableHis {
    border-collapse: collapse;
    width: 25%;
}

.thtdHis {
    padding: 10px;
}






.popup-tab-content {
	border-width: 1 !important;
	border: 1px solid #EEE;
	min-height: 200px;
	*min-height: 225px; /* IE */
}

.tabs-extinfo ul.ui-tabs-nav li {
	font-size: 9px;
	font-weight: normal !important;
}



/* tracks tab */
#tabs-history.ui-tabs.ui-widget-content {
	border: #EEE;
}

#tabs-history .ui-widget-header {
	background: #FFF;
	border: #FFF;
}

#tabs-history .ui-tabs-nav.ui-widget-header {
	padding: 0 0 0;
}

#tabs-history ul.ui-tabs-nav li {
	font-size: 9px;
	font-weight: normal !important;
}

.bottom-border {
	border-bottom: 1px dashed #C5DBEC;
}

.popup-label {
	font-weight: bold;
	width: 105px;
}

.popup-hist-label {
	font-weight: bold;
	width: 155px;
}

div.olLayerGoogleCopyright,div.olLayerGooglePoweredBy {
	display: none !important;
}

button.ui-button-icon-only {
	width: 2.0em;
}

#history-toolbar {
	padding: 0 10 0 10;
}

#history-toolbar .ui-button-icon-only .ui-button-text,.ui-button-icons-only .ui-button-text
	{
	padding: 0 0 0 0;
}

.ui-slider .ui-slider-handle {
	cursor: pointer;
}

.mpointer {
	cursor: pointer;
}

#history-div {
	text-align: center;
	padding-top: 5px;
}

:focus {
	outline: 0;
}

.ui-datepicker {
	width: 16em;
}

.ui-datepicker {
	font-size: 1.0em;
	z-index: 9999 !important;
}

table.reports-fin tr.selected {
	background: #EEE url(images/ui-bg_highlight-hard_100_eeeeee_1x100.png)
		50% 50% repeat-x;
}

.report-map-location {
	background: #a6c9e2;
	cursor: pointer;
}

table#notifiers-tbl {
	border-collapse: collapse;
}

table#notifiers-tbl td {
	border-bottom-style: solid;
	border-bottom-width: 1px;
	padding: 3px;
}

table#notifiers-tbl th {
	padding: 3px;
}

input[type="text"] {
	width: 170px;
}

input[type="text"],input[type="password"] {
	border: 1px solid #B4B4B4;
	color: #464646;
	padding-top: 1px;
	padding-bottom: 1px;
	font-size: 12px;
}

select.text {
	width: 170px;
	border: 1px solid #B4B4B4;
	color: #464646;
	font-size: 12px;
}

select#geozone_type {
	width: 70px;
	border: 1px solid #B4B4B4;
	color: #464646;
	font-size: 12px;
}

div.div-geozone-buttons {
	text-align: right;
	padding-top: 10px;
}

div.div-geozone-buttons input[type="button"] {
	margin-left: 5px;
}

input[type="button"],input[type="submit"],button {
	border: 1px solid #B4B4B4;
	padding-top: 1px;
	padding-bottom: 1px;
	background: #F6F6F6;
	cursor: pointer;
}

input[type="button"] {
	cursor: pointer;
	padding-left: 5px;
	padding-right: 5px;
	padding-top: 0px;
	padding-bottom: 0px;
}

table#geozones-tbl {
	border-collapse: collapse;
}

table#geozones-tbl td {
	border-bottom-style: solid;
	border-bottom-width: 1px;
	padding: 0px 0px;
}

#reports-div {
	height: 300px;
	border: 2px solid #EEE;
	overflow: auto;
}

.left_menu_parent{
	padding-top : 10px;
}

table#mainTable, table#map-tbl {
	border-collapse : collapse;
}

table#mainTable > tbody > tr > td, table#mainTable > tbody > tr > th, 
table#map-tbl > tbody > tr > td, table#map-tbl > tbody > tr > th {
	padding : 0;
}

.sensor-button {
	width: 150px !important;
	padding-left: 10px !important;
	padding-right: 10px !important;
}

div#general-sensor-tab {
	height: 280px;
}

div#graph-sensor-tab {
	height: 280px;
}

input.small {
	width: 70px;
}

.view-map-dialog .ui-dialog-titlebar{
	display: none;
}

.report-cont {
	min-height: 495px;
	*height: 470px;
	overflow: auto;
}

div#admin-accordion .horiz {
	text-align: left;
	width: 0px;
	padding-left: 5px;
}

#admin-accordion .ui-accordion, #admin-accordion .ui-accordion-content {
	padding: 0;
}

#geofence-filter, #notifier-filter, #tracking_interval_div {
	margin-top: 5px;
	border-bottom: 1px dashed #75AD02;
	padding-bottom: 10px;
}
#geofences-tbl {

	padding-top: 10px;
}
.ad-panel-dropdown {

	display: block;
	background-color: #FAFAFA;
	border: 1px solid #9C9DA1; 
	float: right; 
	position: absolute; 
	z-index: 2005;
	padding: 2px;
}
.txt-center {

	text-align:center
}
.gps-bar-2 {

	position: relative;
	left: -3;
}
.gps-state {

	text-align: center;
}
.device-speed {

	width: 50px;
}
.device-fuel{

	width: 50px;
}
.device-taxi{

	width: 50px;
}
.name-header{
	width: 250px;
}
#radio {

	padding-bottom: 10px;
}
#tracks-tbl th {

	padding: 0;
}
#tracks-tbl td {

	padding: 0;
}
.current_language {

	border-style: solid;
	border-bottom-color: #d9d9db;
}

#reports-panel{
	*height: 500px;
}

div.olMap {
    z-index: 0;
    padding: 0 !important;
    margin: 0 !important;
    cursor: default;
}

div.olMapViewport {
    text-align: left;
}

div.olLayerDiv {
   -moz-user-select: none;
   -khtml-user-select: none;
}

.olLayerGoogleCopyright {
    left: 2px;
    bottom: 2px;
}
.olLayerGoogleV3.olLayerGoogleCopyright {
    right: auto !important;
}
.olLayerGooglePoweredBy {
    left: 2px;
    bottom: 15px;   
}
.olLayerGoogleV3.olLayerGooglePoweredBy {
    bottom: 15px !important;
}
.olControlAttribution {
    font-size: smaller; 
    right: 3px; 
    bottom: 4.5em; 
    position: absolute; 
    display: block;
}
.olControlScale {
    right: 3px;
    bottom: 3em;
    display: block;
    position: absolute;
    font-size: smaller;
}
.olControlScaleLine {
   display: block;
   position: absolute;
   left: 10px;
   bottom: 15px;
   font-size: xx-small;
}
.olControlScaleLineBottom {
   border: solid 2px black;
   border-bottom: none;
   margin-top:-2px;
   text-align: center;
}
.olControlScaleLineTop {
   border: solid 2px black;
   border-top: none;
   text-align: center;
}

.olControlPermalink {
    right: 3px;
    bottom: 1.5em;
    display: block;
    position: absolute;
    font-size: smaller;
} 

div.olControlMousePosition {
    bottom: 0em;
    right: 3px;
    display: block;
    position: absolute;
    font-family: Arial;
    font-size: smaller;
}

.olControlOverviewMapContainer {
    position: absolute;
    bottom: 0;
    right: 0;
}

.olControlOverviewMapElement {
    padding: 10px 18px 10px 10px;
    background-color: #00008B;
    -moz-border-radius: 1em 0 0 0;
}

.olControlOverviewMapMinimizeButton {
    right: 0;
    bottom: 80px;
    cursor: pointer;
}    

.olControlOverviewMapMaximizeButton {
    right: 0;
    bottom: 80px;
    cursor: pointer;
}

.olControlOverviewMapExtentRectangle {
    overflow: hidden;
    background-image: url("img/blank.gif");
    cursor: move;
    border: 2px dotted red;
}
.olControlOverviewMapRectReplacement {
    overflow: hidden;
    cursor: move;
    background-image: url("img/overview_replacement.gif");
    background-repeat: no-repeat;
    background-position: center;
}

.olLayerGeoRSSDescription {
    float:left;
    width:100%;
    overflow:auto;
    font-size:1.0em;
}
.olLayerGeoRSSClose {
    float:right;
    color:gray;
    font-size:1.2em;
    margin-right:6px;
    font-family:sans-serif;
}
.olLayerGeoRSSTitle {
    float:left;font-size:1.2em;
}

.olPopupContent {
    padding:5px;
    overflow: auto;
}    

.olControlNavigationHistory {
   background-image: url("img/navigation_history.png");
   background-repeat: no-repeat;
   width:  24px;
   height: 24px;

}
.olControlNavigationHistoryPreviousItemActive { 
  background-position: 0 0;
}
.olControlNavigationHistoryPreviousItemInactive { 
   background-position: 0 -24px;
}
.olControlNavigationHistoryNextItemActive { 
   background-position: -24px 0;
}
.olControlNavigationHistoryNextItemInactive { 
   background-position: -24px -24px;
}

div.olControlSaveFeaturesItemActive { 
    background-image: url(img/save_features_on.png);
    background-repeat: no-repeat;
    background-position: 0 1px;
}
div.olControlSaveFeaturesItemInactive { 
    background-image: url(img/save_features_off.png);
    background-repeat: no-repeat;
    background-position: 0 1px;
}

.olHandlerBoxZoomBox {
    border: 2px solid red;
    position: absolute;
    background-color: white;
    opacity: 0.50;
    font-size: 1px;
    filter: alpha(opacity=50);
}
.olHandlerBoxSelectFeature {
    border: 2px solid blue;
    position: absolute;
    background-color: white;
    opacity: 0.50;
    font-size: 1px;
    filter: alpha(opacity=50);
}   

.olControlPanPanel {
    top: 10px;
    left: 5px;
}  

.olControlPanPanel div {
    background-image: url(img/pan-panel.png);
    height: 18px;
    width: 18px;
    cursor: pointer;
    position: absolute;
}

.olControlPanPanel .olControlPanNorthItemInactive {
    top: 0;
    left: 9px;
    background-position: 0 0;
}
.olControlPanPanel .olControlPanSouthItemInactive {
    top: 36px;
    left: 9px;
    background-position: 18px 0;
}
.olControlPanPanel .olControlPanWestItemInactive {
    position: absolute;
    top: 18px;
    left: 0;
    background-position: 0 18px;
}
.olControlPanPanel .olControlPanEastItemInactive {
    top: 18px;
    left: 18px;
    background-position: 18px 18px;
}

.olControlZoomPanel {
    top: 71px;
    left: 14px;
} 

.olControlZoomPanel div {
    background-image: url(img/zoom-panel.png);
    position: absolute;
    height: 18px;
    width: 18px;
    cursor: pointer;
}

.olControlZoomPanel .olControlZoomInItemInactive {
    top: 0;
    left: 0;
    background-position: 0 0;
}

.olControlZoomPanel .olControlZoomToMaxExtentItemInactive {
    top: 18px;
    left: 0;
    background-position: 0 -18px;
}

.olControlZoomPanel .olControlZoomOutItemInactive {
    top: 36px;
    left: 0;
    background-position: 0 18px;
}

/* 
 * When a potential text is bigger than the image it move the image
 * with some headers (closes #3154) 
 */
.olControlPanZoomBar div {
    font-size: 1px;
}

.olPopupCloseBox {
  background: url("img/close.gif") no-repeat;
  cursor: pointer;
}

.olFramedCloudPopupContent {
    padding: 5px;
    overflow: auto;
}

.olControlNoSelect {
 -moz-user-select: none;
 -khtml-user-select: none;
}

.olImageLoadError {
    background-color: pink;
    opacity: 0.5;
    filter: alpha(opacity=50); /* IE */
}

/**
 * Cursor styles
 */

.olCursorWait {
    cursor: wait;
}
.olDragDown {
    cursor: move;
}
.olDrawBox {
    cursor: crosshair;
}
.olControlDragFeatureOver {
    cursor: move;
}
.olControlDragFeatureActive.olControlDragFeatureOver.olDragDown {
    cursor: -moz-grabbing;
}

/**
 * Layer switcher
 */
.olControlLayerSwitcher {
    position: absolute;
    top: 25px;
    right: 0;
    width: 20em;
    font-family: sans-serif;
    font-weight: bold;
    margin-top: 3px;
    margin-left: 3px;
    margin-bottom: 3px;
    font-size: smaller;
    color: white;
    background-color: transparent;
}

.olControlLayerSwitcher .layersDiv {
    padding-top: 5px;
    padding-left: 10px;
    padding-bottom: 5px;
    padding-right: 75px;
    background-color: darkblue;
    width: 100%;
    height: 100%;
}

.olControlLayerSwitcher .layersDiv .baseLbl,
.olControlLayerSwitcher .layersDiv .dataLbl {
    margin-top: 3px;
    margin-left: 3px;
    margin-bottom: 3px;
}

.olControlLayerSwitcher .layersDiv .baseLayersDiv,
.olControlLayerSwitcher .layersDiv .dataLayersDiv {
    padding-left: 10px;
}

.olControlLayerSwitcher .maximizeDiv,
.olControlLayerSwitcher .minimizeDiv {
    top: 5px;
    right: 0;
    cursor: pointer;
}

.olBingAttribution {
    color: #DDD;
}
.olBingAttribution.road {
    color: #333;
}

.olGoogleAttribution.hybrid, .olGoogleAttribution.satellite {
    color: #EEE;
}
.olGoogleAttribution {
    color: #333;
}
span.olGoogleAttribution a {
    color: #77C;
}
span.olGoogleAttribution.hybrid a, span.olGoogleAttribution.satellite a {
    color: #EEE;
}

/**
 * Editing and navigation icons.
 * (using the editing_tool_bar.png sprint image)
 */
.olControlNavToolbar ,
.olControlEditingToolbar {
    margin: 5px 5px 0 0;
}
.olControlNavToolbar div,
.olControlEditingToolbar div {
    background-image: url("img/editing_tool_bar.png");
    background-repeat: no-repeat;
    margin: 0 0 5px 5px;
    width: 24px;
    height: 22px;
    cursor: pointer
}
/* positions */
.olControlEditingToolbar {
    right: 0;
    top: 0;
}
.olControlNavToolbar {
    top: 295px;
    left: 9px;
}
/* layouts */
.olControlEditingToolbar div {
    float: right;
}
