}
.jqx-element {
    overflow: hidden;
    border-style: solid;
    border-width: 0px;
    border-color: transparent;
    box-sizing:border-box;
}
.jqx-element-no-border {
    border-width:0px;
}
.jqx-element-container {
}
.jqx-resize-trigger, .jqx-resize-trigger-shrink {
    position: absolute; 
    left: 0; 
    top: 0; 
    transition: 0s
}
.jqx-resize-trigger-shrink {
    width: 200%; 
    height: 200%;
}
.jqx-resize-trigger-container {
    display: block;
    visibility:hidden;
    position: relative;
    top: -100%; 
    left: 0; 
    min-height:0.1px;
    height: 100%; 
    width: 100%; 
    overflow: hidden; 
    pointer-events: none; 
    z-index: -1;
    visibility:hidden;
}

/* jqxPivotGrid */
.jqx-pivotgrid
{
    background-color: #DEDEDE;
}

.jqx-pivotgrid-item
{
    white-space: nowrap;
    overflow: hidden;
    position: absolute;
    padding: 0px;
    text-overflow: ellipsis;
}

.jqx-pivotgrid-content-wrapper
{
    align: left;
    valign: top;
    overflow: hidden;
    border: solid 1px grey;
}

.jqx-pivotgrid-menu-button
{
    border: none;
    background-image: url('images/icon-menu-small.png');
    background-repeat: no-repeat;
    background-position: center;
