/* A CSS Framework by Mike Stenhouse of Content with Style */

/* NAV */
    div#nav {
        font-size: 0.8em;
	    padding: 0;
    	height: 35px; 
    	border-bottom: 5px solid #d9d9db;

    }

    div#navigationPanel {
        border-bottom: 1px solid #CCCCCC;
        width: 100%;
    }

    div#nav ul {
        width: auto;
        margin: 0;
        padding: 0;
        line-height: 1em;
        list-style: none;
    }

    div#nav li {
        float: left;
        display: inline;
        list-style: none;
        margin: 0;
        padding: 0px 15px 0 0;
        font-size: 1.3em;
    }

    div#nav a,
    div#nav a:link,
    div#nav a:active,
    div#nav a:visited {
        display: inline-block;
        /* hide from ie/mac \*/
        display: block;
        /* end hide */
        font-weight: bold;
        text-decoration: none;
        margin: 0 auto;
		color: black;
		height: 25px;
		width: 100px;
		background: #EEEEEE;
		background: -moz-linear-gradient(#FDFDFD, #EEEEEE) repeat scroll 0 0 #EEEEEE;
		background: -webkit-linear-gradient( #FDFDFD, #EEEEEE );
   		background: -o-linear-gradient( #FDFDFD, #EEEEEE );
   		border: 1px solid #CCCCCC;
   		color: #444444;
   		text-shadow: 0 1px 1px #F6F6F6;	
   		box-shadow: 0 1px 4px rgba(0, 0, 0, 0.3);
   		border-radius: 0.5em 0.5em 0.5em 0.5em;
   		text-align: center;

    }

    div#nav a:hover{
		background: -moz-linear-gradient(#EDEDED, #DADADA) repeat scroll 0 0 #DADADA;
    }

    div#nav a.current {
    	background: -moz-linear-gradient(#d0ef62, #75ad02) repeat scroll 0 0 #75ad02;
    	background: -webkit-linear-gradient( #d0ef62 , #75ad02 );
    	background: -o-linear-gradient( #d0ef62 , #75ad02 );
   		text-shadow: none;
   		border: 1px solid #94cb1f;
		color: white;
	}

    div#nav .pad {
       padding-left: 10px;
    }

    .horiz {
    	display: table-cell; 
    	vertical-align: middle;
		height: 25px;
   		width: 95px;
   		text-align: center;

    }

    .span-table-menu{
    	display: table; 
    	margin: 0 auto; 
    	text-align: center;
    }

    .menuItem{
    	background: none;
    	border: none;
    	padding-left: 1px;
    }

    .logo{
    	padding: 0px 15px 0 10px; 
    	height: 30px; 
    	position: relative; 
    	top: -10px; 
    	float:left;
    }
/* END NAV */

